import { ParserRegistry } from '../core/parser-registry';
import { getBaseMark4BarMarker } from '../bar/bar-marker-helpers';

export function _markerMark(data, phase, condition) {
    const KEY = 'marker';
    let _markerG = {
        mark: 'g',
        selector: `.subseries_marker${this.builderC.datasetIndex}`,
        data: data.disabled || !condition ? [] : [data.data],
        children: []
    };

    let highlightPhase = phase === 'highlight',
        isMarkerOnBothEdges = this.builderC.commonPlotOptions[KEY].start.size && this.builderC.commonPlotOptions[KEY].end.size,
        options = highlightPhase ? this.builderC.commonPlotOptions[KEY].hoveroptions : this.builderC.commonPlotOptions[KEY];

    if(condition){
        let args_data = highlightPhase ? data.data : null;
        if(isMarkerOnBothEdges) {
            // let markerMark_0 = getBaseMark4BarMarker.call(this, KEY, args_data, options.start, 0),
            //     markerMark_1 = getBaseMark4BarMarker.call(this, KEY, args_data, options.end, 1);
            // _markerG.children.push(markerMark_0, markerMark_1);
            let markerMark_0_outer = getBaseMark4BarMarker.call(this, KEY, args_data, options.start, 0, 'outer'),
                markerMark_0_inner = getBaseMark4BarMarker.call(this, KEY, args_data, options.start, 0, 'inner'),
                markerMark_1_outer = getBaseMark4BarMarker.call(this, KEY, args_data, options.end, 1, 'outer'),
                markerMark_1_inner = getBaseMark4BarMarker.call(this, KEY, args_data, options.end, 1, 'inner');
            _markerG.children.push(markerMark_0_outer, markerMark_0_inner, markerMark_1_outer, markerMark_1_inner);
        }
        else {
            let pos = options.start.size > 0 ? 'start': 'end';
            // let markerMark = getBaseMark4BarMarker.call(this, KEY, args_data, options[pos], 0);
            // _markerG.children.push(markerMark);
            let markerMark_outer = getBaseMark4BarMarker.call(this, KEY, args_data, options[pos], 0, 'outer');
            let markerMark_inner = getBaseMark4BarMarker.call(this, KEY, args_data, options[pos], 0, 'inner');
            _markerG.children.push(markerMark_outer, markerMark_inner);
        }
    }

    return _markerG;
}

ParserRegistry.marks('gantt.marker', _markerMark);
